          transition={{ duration: 0.4, ease: 'easeOut', delay: 0.1 }}
          style={{ fontSize: '16px', color: '#6B7280', lineHeight: '1.6', textAlign: 'center' }}
          className="mb-12"
        >
          {t('home.bookDemo.subtitle')}
        </motion.p>

        {/* CTA Button */}
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, ease: 'easeOut', delay: 0.2 }}
        >
          <Link to="/book-demo">
            <button
              className="px-12 py-4 font-medium transition-all duration-200 hover:opacity-90"
              style={{ 
                backgroundColor: '#2D472C', 
                color: 'white', 
                borderRadius: '4px',
                fontSize: '15px',
                fontWeight: '600'
              }}
            >
              {t('home.bookDemo.cta')}
            </button>
          </Link>

          {/* Trust indicators */}
          <div className="flex flex-wrap justify-center gap-6 mt-8 text-sm" style={{ color: '#6B7280' }}>
            <div className="flex items-center gap-2">
              <CheckCircle size={16} style={{ color: '#C5A059' }} />
              <span>{t('home.bookDemo.trust.fastResponse')}</span>
            </div>
            <div className="flex items-center gap-2">
              <CheckCircle size={16} style={{ color: '#C5A059' }} />
              <span>{t('home.bookDemo.trust.freeDemo')}</span>
            </div>
            <div className="flex items-center gap-2">
              <CheckCircle size={16} style={{ color: '#C5A059' }} />
              <span>{t('home.bookDemo.trust.noCommitment')}</span>
            </div>
          </div>
        </motion.div>
      </div>
    </section>
  );
}

.heroSecondaryCta {
  height: 48px;
  padding: 0 28px;
  border-radius: 9999px; /* span-like pill */

  border: 1px solid rgba(45, 71, 44, 0.35);
  background: rgba(255, 255, 255, 0.65);
  backdrop-filter: blur(10px);

  color: #2d472c;
  font-size: 15px;
  font-weight: 600;
  letter-spacing: -0.01em;

  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;

  box-shadow: 0 10px 35px rgba(17, 24, 39, 0.08);

  transition:
    transform 180ms ease,
    box-shadow 180ms ease,
    background-color 180ms ease,
    border-color 180ms ease;

  cursor: pointer;
}

.heroSecondaryCta__label {
  position: relative;
}

.heroSecondaryCta:hover {
  transform: translateY(-1px);
  box-shadow: 0 18px 55px rgba(17, 24, 39, 0.14);
  border-color: rgba(45, 71, 44, 0.55);
  background: rgba(255, 255, 255, 0.8);
}

.heroSecondaryCta:active {
  transform: translateY(0);
  box-shadow: 0 10px 35px rgba(17, 24, 39, 0.10);
}

.heroSecondaryCta:focus-visible {
