import { Globe } from 'lucide-react';
import { useTranslation } from 'react-i18next';

const LANGS = [
  { code: 'en', label: 'EN' },
  { code: 'fr', label: 'FR' },
  { code: 'ar', label: 'AR' },
] as const;

export function LanguageSwitcher() {
  const { i18n, t } = useTranslation();

  const current = ((i18n.resolvedLanguage || i18n.language || 'fr').split('-')[0] as
    | 'en'
    | 'fr'
    | 'ar');

  return (
    <div className="flex items-center gap-2">
      <Globe size={18} className="text-[#6B7280]" />
      <select
        aria-label={t('common.language')}
        value={current}
        onChange={(e) => i18n.changeLanguage(e.target.value)}
        className="text-sm bg-transparent border border-[#E5E7EB] rounded-md px-2 py-1 text-[#374151]"
      >
        {LANGS.map((l) => (
          <option key={l.code} value={l.code}>
            {l.label}
          </option>
        ))}
      </select>
    </div>
  );
}

/* Navbar refinements (premium glass + better hover + active underline) */

.navbarRoot {
  background: rgba(255, 255, 255, 0.82);
  -webkit-backdrop-filter: blur(14px);
  backdrop-filter: blur(14px);
}

.navbarRoot.navbarRoot--scrolled {
  border-bottom: 1px solid rgba(229, 231, 235, 0.9);
  box-shadow: 0 10px 30px rgba(17, 24, 39, 0.06);
}

.navbarInner {
  height: 76px;
}

.navbarLogo {
  display: inline-flex;
  align-items: center;
  gap: 10px;
}

.navbarLogo img {
  height: 46px;
  width: auto;
  display: block;
}

.navbarLink {
  position: relative;
  color: #6B7280;
  font-size: 14px;
  font-weight: 500;
  letter-spacing: -0.01em;
  transition: color 160ms ease;
}

.navbarLink:hover {
  color: #2D472C;
}

.navbarLink::after {
  content: '';
  position: absolute;
  left: 0;
  bottom: -10px;
  width: 100%;
  height: 2px;
  border-radius: 9999px;
  background: linear-gradient(90deg, rgba(45,71,44,0) 0%, rgba(45,71,44,0.65) 45%, rgba(45,71,44,0) 100%);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 180ms ease;
  opacity: 0.9;
}

.navbarLink:hover::after {
  transform: scaleX(1);
}

.navbarDropdownBtn {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: #6B7280;
  font-size: 14px;
  font-weight: 500;
  letter-spacing: -0.01em;
  transition: color 160ms ease;
}

.navbarDropdownBtn:hover {
  color: #2D472C;
}

.navbarDropdownMenu {
  width: 240px;
  background: rgba(255, 255, 255, 0.92);
  border-radius: 14px;
  border: 1px solid rgba(229, 231, 235, 0.9);
  box-shadow: 0 28px 90px rgba(17, 24, 39, 0.18);
  overflow: hidden;
}

.navbarDropdownItem {
  padding: 12px 14px;
  color: #111827;
  font-size: 14px;
  font-family: Inter, sans-serif;
  display: flex;
  align-items: center;
  gap: 10px;
  transition: background-color 160ms ease;
}

.navbarDropdownItem:hover {
  background-color: rgba(249, 249, 247, 1);
}

.navbarCta {
  height: 44px;
  padding: 0 18px;
  border-radius: 9999px;
  background: linear-gradient(135deg, rgba(45,71,44,1) 0%, rgba(33,55,32,1) 100%);
  box-shadow: 0 18px 50px rgba(45, 71, 44, 0.22);
  transition: transform 160ms ease, box-shadow 160ms ease, opacity 160ms ease;
}

.navbarCta:hover {
  transform: translateY(-1px);
  box-shadow: 0 26px 70px rgba(45, 71, 44, 0.28);
  opacity: 0.98;
}

.navbarCta:active {
  transform: translateY(0);
  box-shadow: 0 18px 50px rgba(45, 71, 44, 0.22);
}

.navbarCta:focus-visible {
  outline: none;
  box-shadow: 0 0 0 4px rgba(197, 160, 89, 0.30), 0 26px 70px rgba(45, 71, 44, 0.28);
}

