import { motion } from 'motion/react';
import { GraduationCap, Users, LayoutDashboard, BarChart2, ChevronDown } from 'lucide-react';
import { Link } from 'react-router';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { LanguageSwitcher } from './LanguageSwitcher';
import logoImage from '../../assets/logooo.png';
import './Navbar.css';

interface NavbarProps {
  scrolled: boolean;
}

export function Navbar({ scrolled }: NavbarProps) {
  const [applicationsOpen, setApplicationsOpen] = useState(false);
  const { t } = useTranslation();

  const applicationItems = [
    { icon: GraduationCap, label: t('nav.apps.teacher'), path: '/app/teacher' },
    { icon: Users, label: t('nav.apps.parent'), path: '/app/parent' },
    { icon: LayoutDashboard, label: t('nav.apps.assistant'), path: '/app/assistant' },
    { icon: BarChart2, label: t('nav.apps.manager'), path: '/app/manager' },
  ];

  return (
    <motion.nav
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.4, ease: 'easeOut' }}
      className={`navbarRoot fixed top-0 left-0 right-0 z-50 transition-all duration-200 ${
        scrolled ? 'navbarRoot--scrolled' : ''
      }`}
    >
      <div className="navbarInner max-w-7xl mx-auto px-6 flex items-center justify-between">
        {/* Logo */}
        <Link to="/" className="navbarLogo">
          <img src={logoImage} alt={t('common.brand')} />
        </Link>

        {/* Center Navigation */}
        <div className="hidden md:flex items-center gap-8">
          <Link to="/" className="navbarLink">
            {t('nav.home')}
          </Link>

          <Link to="/solution" className="navbarLink">
            {t('nav.solutions')}
          </Link>

          {/* Applications Dropdown */}
          <div
            className="relative"
            onMouseEnter={() => setApplicationsOpen(true)}
            onMouseLeave={() => setApplicationsOpen(false)}
          >
            <button type="button" className="navbarDropdownBtn" aria-expanded={applicationsOpen}>
              {t('nav.applications')}
              <ChevronDown size={16} style={{ opacity: 0.9 }} />
            </button>

            {applicationsOpen && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.2 }}
                className="absolute top-full left-0 pt-3"
                style={{ zIndex: 100 }}
              >
                <div className="navbarDropdownMenu">
                  {applicationItems.map((item, index) => (
                    <div key={item.path}>
                      <Link to={item.path} className="navbarDropdownItem">
                        <item.icon size={16} style={{ color: '#2D472C', opacity: 0.95 }} />
                        <span>{item.label}</span>
                      </Link>

                      {index < applicationItems.length - 1 && (
                        <div style={{ height: '1px', backgroundColor: 'rgba(229,231,235,0.65)' }} />
                      )}
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </div>

          <Link to="/contact" className="navbarLink">
            {t('nav.contact')}
          </Link>

          <Link to="/about" className="navbarLink">
            {t('nav.about')}
          </Link>
        </div>

        {/* Right Side */}
        <div className="flex items-center gap-4">
          <LanguageSwitcher />

          <Link to="/book-demo">
            <button className="navbarCta px-5 text-sm font-medium" style={{ color: 'white' }}>
              {t('nav.bookDemo')}
            </button>
          </Link>
        </div>
      </div>
    </motion.nav>
  );
}

import { motion } from 'motion/react';
import { CheckCircle2 } from 'lucide-react';
import { ImageWithFallback } from './figma/ImageWithFallback';
import cap4 from '../../assets/cap4.png';
import { useTranslation } from 'react-i18next';

export function OverviewSection() {
  const { t } = useTranslation();

  const features = t('home.overviewSection.features', { returnObjects: true }) as string[];

  return (
    <section className="py-20 px-6" style={{ backgroundColor: 'white' }}>
      <div className="max-w-[1320px] mx-auto">
        <div className="grid lg:grid-cols-[58%_42%] gap-16 items-center">
          {/* Left Side - Image */}
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, ease: 'easeOut' }}
          >
            <div
              className="relative"
              style={{
                borderRadius: '16px',
                overflow: 'hidden',
                boxShadow: '0 22px 70px rgba(0, 0, 0, 0.12)',
                border: '1px solid rgba(0,0,0,0.08)',
                // Slightly wider visual presence on desktop
                width: 'calc(100% + 36px)',
                maxWidth: 'calc(100% + 36px)',
              }}
            >
              {/*
               * Use a fixed-height container for consistent display and better clarity.
               * On large screens we show more of the image.
               */}
              <div className="w-full h-[320px] sm:h-[420px] lg:h-[520px]">
                <ImageWithFallback
                  src={cap4}
                  alt={t('home.overviewSection.imageAlt')}
                  className="w-full h-full object-cover"
                  style={{
                    objectPosition: 'center',
                  }}
                />
              </div>

              {/* Very light overlay (keeps brand feel but doesn't darken the image) */}
              <div
                className="absolute inset-0"
                style={{
                  background:
                    'linear-gradient(135deg, rgba(45, 71, 44, 0.08) 0%, rgba(45, 71, 44, 0.00) 45%, rgba(197, 160, 89, 0.06) 100%)',
                  pointerEvents: 'none',
                }}
              />

              {/* Subtle highlight border */}
              <div
                className="absolute inset-0"
                style={{
                  borderRadius: '16px',
                  boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.55)',
                  pointerEvents: 'none',
                }}
              />
            </div>
          </motion.div>

          {/* Right Side - Text Content */}
          <motion.div
            initial={{ opacity: 0, x: 20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6, ease: 'easeOut', delay: 0.2 }}
            className="space-y-6"
          >
            {/* Title */}
            <h2
              style={{
                fontFamily: 'Montserrat, sans-serif',
                fontSize: '36px',
                fontWeight: '700',
                color: '#333333',
                lineHeight: '1.2',
                letterSpacing: '-0.01em'
              }}
            >
              {t('home.overviewSection.title')}
            </h2>

            {/* Feature Checklist */}
            <div className="space-y-3 pt-2">
              {features.map((feature, index) => (
                <motion.div
                  key={`${feature}-${index}`}
                  initial={{ opacity: 0, x: -10 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.3, ease: 'easeOut', delay: 0.05 * index }}
                  className="flex items-center gap-3"
                >
                  <CheckCircle2
                    size={20}
                    style={{ color: '#C5A059', flexShrink: 0 }}
                    fill="#C5A059"
                  />
                  <span style={{ fontSize: '15px', color: '#333333', lineHeight: '1.5' }}>
                    {feature}
                  </span>
                </motion.div>
              ))}
            </div>
          </motion.div>
        </div>
      </div>
    </section>
  );
}

/* Vision / ProblemSection (NOTRE VISION) */

.visionSection {
  position: relative;
  background: #ffffff;
}

.visionContainer {
  max-width: 1120px;
  margin: 0 auto;
}

.visionBadge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 14px;
  border-radius: 9999px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: #c5a059;
  background: rgba(197, 160, 89, 0.10);
  border: 1px solid rgba(197, 160, 89, 0.22);
}

.visionTitle {
  font-family: Montserrat, sans-serif;
  font-size: 42px;
  font-weight: 800;
  color: #2D472C;
  letter-spacing: -0.02em;
  line-height: 1.15;
}

.visionText {
  text-align: center;
  max-width: 820px;
  margin: 0 auto 64px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.visionParagraph {
  font-family: Inter, sans-serif;
  font-size: 16px;
  color: #6B7280;
  line-height: 1.95;
  margin: 0;
}

/* subtle highlight for key phrases */
.visionParagraph strong {
  color: #374151;
  font-weight: 700;
}

.visionStats {
  display: flex;
  align-items: stretch;
  justify-content: center;
  gap: 48px;
  flex-wrap: wrap;
}

.visionStat {
  display: flex;
  align-items: center;
}

.visionStatNumber {
  font-family: Montserrat, sans-serif;
  font-size: 40px;
  font-weight: 800;
  color: #2D472C;
  margin-bottom: 8px;
}

.visionStatLabel {
  font-family: Inter, sans-serif;
  font-size: 14px;
  color: #6B7280;
}

.visionDivider {
  width: 1px;
  height: 60px;
  background-color: #E5E7EB;
  margin-left: 48px;
}

/* Decorative glow */
.visionGlow {
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(900px 460px at 50% 30%, rgba(45, 71, 44, 0.08) 0%, rgba(45, 71, 44, 0.00) 60%),
    radial-gradient(640px 380px at 70% 10%, rgba(197, 160, 89, 0.10) 0%, rgba(197, 160, 89, 0.00) 65%);
}

