/* About page - Who we are right image (part.png) */

.about-who-media {
  width: 100%;
  max-width: 580px;
  aspect-ratio: 580 / 380;
  border-radius: 16px;
  overflow: hidden;

  /* App-like contour */
  border: 1.5px solid rgba(45, 71, 44, 0.28);

  /* Subtle layered shadow + green halo */
  box-shadow:
    0 10px 30px rgba(0, 0, 0, 0.08),
    0 0 0 6px rgba(45, 71, 44, 0.06),
    0 26px 70px rgba(45, 71, 44, 0.12);

  background:
    radial-gradient(120% 120% at 0% 0%, rgba(197, 160, 89, 0.18) 0%, rgba(255, 255, 255, 0) 55%),
    linear-gradient(135deg, rgba(45, 71, 44, 0.10), rgba(197, 160, 89, 0.08));

  transform: translateZ(0);
  transition: transform 220ms ease, box-shadow 220ms ease, border-color 220ms ease;
}

.about-who-media:hover {
  transform: translateY(-3px);
  border-color: rgba(45, 71, 44, 0.45);
  box-shadow:
    0 14px 40px rgba(0, 0, 0, 0.10),
    0 0 0 7px rgba(45, 71, 44, 0.08),
    0 34px 90px rgba(45, 71, 44, 0.16);
}

.about-who-media__img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;

  filter: saturate(1.05) contrast(1.03);
}

/* About page - Text blocks (À propos & Notre Culture) */

.about-text {
  max-width: 520px;
}

.about-text__lead {
  font-size: 15px;
  color: #6B7280;
  line-height: 1.8;
  margin: 0 0 16px 0;
}

.about-text__bullets {
  margin: 0;
  padding-left: 18px;
  display: grid;
  gap: 12px;
  color: #6B7280;
}

.about-text__bullets li {
  font-size: 15px;
  line-height: 1.8;
}

.about-text__paragraph {
  font-size: 15px;
  color: #6B7280;
  line-height: 1.8;
  max-width: 460px;

  /* subtle left accent (app-like) */
  padding-left: 14px;
  border-left: 3px solid rgba(45, 71, 44, 0.18);
}

.about-text__paragraph + .about-text__paragraph {
  margin-top: 14px;
}

/* About page - Culture image (Culturr.png) */

.about-culture-media {
  width: 100%;
  max-width: 560px;

  /* keep a stable layout; adjust ratio if your asset differs */
  aspect-ratio: 560 / 380;

  position: relative;
  overflow: hidden;
  border-radius: 22px;

  /* glassy frame + warm accent */
  border: 1px solid rgba(255, 255, 255, 0.55);
  background:
    radial-gradient(100% 140% at 0% 0%, rgba(197, 160, 89, 0.22) 0%, rgba(255, 255, 255, 0) 58%),
    radial-gradient(120% 120% at 100% 110%, rgba(45, 71, 44, 0.14) 0%, rgba(255, 255, 255, 0) 55%),
    linear-gradient(135deg, rgba(45, 71, 44, 0.08), rgba(197, 160, 89, 0.08));

  box-shadow:
    0 18px 50px rgba(0, 0, 0, 0.10),
    0 0 0 8px rgba(45, 71, 44, 0.06),
    0 40px 110px rgba(45, 71, 44, 0.14);

  transform: translateZ(0);
  transition: transform 260ms ease, box-shadow 260ms ease, border-color 260ms ease, filter 260ms ease;
}

/* Replace the mask-based border (can look broken depending on browser) with a clean inset outline */
.about-culture-media::before {
  content: '';
  position: absolute;
  inset: 10px;
  pointer-events: none;
  border-radius: 16px;
  border: 1px solid rgba(197, 160, 89, 0.22);
  opacity: 0.95;
  z-index: 2;
}

/* Soft aura layer */
.about-culture-media::after {
  content: '';
  position: absolute;
  inset: -45%;
  pointer-events: none;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 25%, rgba(197, 160, 89, 0.26), rgba(197, 160, 89, 0.0) 55%),
    radial-gradient(circle at 70% 80%, rgba(45, 71, 44, 0.18), rgba(45, 71, 44, 0.0) 58%);
  opacity: 0.40;
  filter: blur(18px);
  transform: translate3d(-4%, 6%, 0);
  z-index: 0;
}

.about-culture-media__img {
  /* ensure crisp rounded contour */
  border-radius: 22px;
  position: relative;
  z-index: 1;
}

.about-culture-media__shine {
  z-index: 3;
}

/* top highlight glaze */
.about-culture-media__shine {
  position: absolute;
  inset: -55% -65%;
  pointer-events: none;
  background: linear-gradient(
    110deg,
    rgba(255, 255, 255, 0) 35%,
    rgba(255, 255, 255, 0.32) 50%,
    rgba(255, 255, 255, 0) 65%
  );
  transform: rotate(10deg) translateX(-35%);
  opacity: 0.0;
  mix-blend-mode: overlay;
}

.about-culture-media:hover .about-culture-media__shine {
  animation: aboutCultureShine 1.15s ease-in-out;
}

@keyframes aboutCultureShine {
  0% {
    transform: rotate(10deg) translateX(-55%);
    opacity: 0.0;
  }
  30% {
    opacity: 0.38;
  }
  100% {
    transform: rotate(10deg) translateX(55%);
    opacity: 0.0;
  }
}

@media (prefers-reduced-motion: reduce) {
  .about-culture-media,
  .about-culture-media__img {
    transition: none;
  }
  .about-culture-media:hover .about-culture-media__shine {
    animation: none;
    opacity: 0.0;
  }
}

