    0 0 0 8px rgba(45, 71, 44, 0.06),
    0 40px 110px rgba(45, 71, 44, 0.14);

  transform: translateZ(0);
  transition: transform 260ms ease, box-shadow 260ms ease, border-color 260ms ease, filter 260ms ease;
}

/* Replace the mask-based border (can look broken depending on browser) with a clean inset outline */
.about-culture-media::before {
  content: '';
  position: absolute;
  inset: 10px;
  pointer-events: none;
  border-radius: 16px;
  border: 1px solid rgba(197, 160, 89, 0.22);
  opacity: 0.95;
  z-index: 2;
}

/* Soft aura layer */
.about-culture-media::after {
  content: '';
  position: absolute;
  inset: -45%;
  pointer-events: none;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 25%, rgba(197, 160, 89, 0.26), rgba(197, 160, 89, 0.0) 55%),
    radial-gradient(circle at 70% 80%, rgba(45, 71, 44, 0.18), rgba(45, 71, 44, 0.0) 58%);
  opacity: 0.40;
  filter: blur(18px);
  transform: translate3d(-4%, 6%, 0);
  z-index: 0;
}

.about-culture-media__img {
  /* ensure crisp rounded contour */
  border-radius: 22px;
  position: relative;
  z-index: 1;
}

.about-culture-media__shine {
  z-index: 3;
}

/* top highlight glaze */
.about-culture-media__shine {
  position: absolute;
  inset: -55% -65%;
  pointer-events: none;
  background: linear-gradient(
    110deg,
    rgba(255, 255, 255, 0) 35%,
    rgba(255, 255, 255, 0.32) 50%,
    rgba(255, 255, 255, 0) 65%
  );
  transform: rotate(10deg) translateX(-35%);
  opacity: 0.0;
  mix-blend-mode: overlay;
}

.about-culture-media:hover .about-culture-media__shine {
  animation: aboutCultureShine 1.15s ease-in-out;
}

@keyframes aboutCultureShine {
  0% {
    transform: rotate(10deg) translateX(-55%);
    opacity: 0.0;
  }
  30% {
    opacity: 0.38;
  }
  100% {
    transform: rotate(10deg) translateX(55%);
    opacity: 0.0;
  }
}

@media (prefers-reduced-motion: reduce) {
  .about-culture-media,
  .about-culture-media__img {
    transition: none;
  }
  .about-culture-media:hover .about-culture-media__shine {
    animation: none;
    opacity: 0.0;
  }
}

/* About page - CTA buttons */

.about-cta__link {
  text-decoration: none;
}

.about-cta__btn {
  height: 48px;
  padding: 0 28px;
  border-radius: 12px;
  font-size: 15px;
  font-weight: 700;
  letter-spacing: 0.01em;
  border: 1px solid transparent;
  cursor: pointer;

  display: inline-flex;
  align-items: center;
  justify-content: center;

  transition: transform 160ms ease, box-shadow 160ms ease, background-color 160ms ease, border-color 160ms ease, color 160ms ease;
}

.about-cta__btn:focus-visible {
  outline: none;
  box-shadow: 0 0 0 4px rgba(197, 160, 89, 0.35);
}

.about-cta__btn--primary {
  background: linear-gradient(180deg, #D6B26A 0%, #C5A059 100%);
  color: #20361f;
  box-shadow: 0 14px 30px rgba(0, 0, 0, 0.18);
}

.about-cta__btn--primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 18px 42px rgba(0, 0, 0, 0.22);
}

.about-cta__btn--primary:active {
  transform: translateY(0);
}

.about-cta__btn--secondary {
  background: rgba(255, 255, 255, 0.10);
  color: #ffffff;
  border-color: rgba(255, 255, 255, 0.55);
  box-shadow: 0 10px 26px rgba(0, 0, 0, 0.16);
  backdrop-filter: blur(6px);
}

.about-cta__btn--secondary:hover {
  transform: translateY(-2px);
  background: rgba(255, 255, 255, 0.16);
  border-color: rgba(255, 255, 255, 0.75);
  box-shadow: 0 16px 40px rgba(0, 0, 0, 0.22);
}

.about-cta__btn--secondary:active {
  transform: translateY(0);
}

@media (max-width: 420px) {
  .about-cta__btn {
    width: 100%;
    max-width: 320px;
  }
}

