                  >
                    {t('assistantDashboard.lightbox.previous')}
                  </button>
                  <button
                    type="button"
                    className="px-3 py-1.5 rounded-md text-[12px] transition-opacity duration-200 hover:opacity-80"
                    style={{ backgroundColor: '#F3F4F6', color: '#111827' }}
