                              border: formData.apps.teacher ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.teacher ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                        <label
                    <p style={{ fontSize: '15px', color: '#6B7280', marginBottom: '32px' }}>
                      Nous vous contacterons dans les 24 heures pour confirmer votre démonstration.
                    </p>
                          htmlFor="message"
                        >
                          Message (optionnel)
                              transition: 'all 0.2s ease-out',
                      Demande Envoyée!
                          >
                            <GraduationCap size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>App Enseignant</span>
                            {formData.apps.teacher && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          placeholder="Dites-nous en plus sur votre école et vos besoins..."

                          <div
                            onClick={() => handleCheckboxChange('parent')}
                            style={{
                              border: formData.apps.parent ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.parent ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                        Retour à l'accueil
                            }}
                          >
                            <Users size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>App Parent</span>
                            {formData.apps.parent && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('manager')}
                            style={{
                              border: formData.apps.manager ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.manager ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <BarChart2 size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>Dashboard Manager</span>
                            {formData.apps.manager && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>
                        </div>
                        {isSubmitting ? 'Envoi en cours…' : 'Envoyer ma Demande de Démo →'}

                      {/* Row 6 - Message */}
                      <div style={{ marginBottom: '24px' }}>
                      <div
                        style={{
                          fontSize: '12px',
                          color: '#9CA3AF',
                          textAlign: 'center',
                          marginTop: '12px',
                        }}
                      >
                        ✓ Réponse sous 24h ✓ Démo gratuite ✓ Sans engagement
                          htmlFor="message"
                        >
                          Message (optionnel)
                        </label>
                        <textarea
                          id="message"
                          name="message"
                          value={formData.message}
                          onChange={handleInputChange}
                          placeholder="Dites-nous en plus sur votre école et vos besoins..."
                          rows={4}
                    <p style={{ fontSize: '15px', color: '#6B7280', marginBottom: '32px' }}>
                      Nous vous contacterons dans les 24 heures pour confirmer votre démonstration.
                    </p>
                            width: '100%',
                            border: '1px solid #E5E7EB',
                            borderRadius: '4px',
                            padding: '12px',
                      Demande Envoyée!
                            color: '#333333',
                            fontFamily: 'Inter, sans-serif',
                            resize: 'vertical',
                            minHeight: '100px',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        />
                      </div>

                      {/* Submit Button */}
                      <button
                        type="submit"
                        disabled={isSubmitting}
                        style={{
                          width: '100%',
                          height: '48px',
                        Retour à l'accueil
                          color: 'white',
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '15px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          border: 'none',
                          cursor: isSubmitting ? 'not-allowed' : 'pointer',
                          opacity: isSubmitting ? 0.75 : 1,
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '0.9';
                        }}
                        onMouseLeave={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '1';
                        }}
                      >
                        {isSubmitting ? 'Envoi en cours…' : 'Envoyer ma Demande de Démo →'}
                      </button>

                      {/* Note */}
                      <div
                        style={{
                          fontSize: '12px',
                          color: '#9CA3AF',
                          textAlign: 'center',
                          marginTop: '12px',
                        }}
                      >
                        ✓ Réponse sous 24h ✓ Démo gratuite ✓ Sans engagement
                      </div>
                    </form>
                  </>
                ) : (
                  /* Success State */
                  <div style={{ textAlign: 'center', padding: '40px 0' }}>
                    <CheckCircle size={64} style={{ color: '#C5A059', margin: '0 auto 24px' }} />
                    <h2
                      style={{
                        fontFamily: 'Montserrat, sans-serif',
                        fontSize: '24px',
                        fontWeight: '700',
                        color: '#333333',
                        marginBottom: '12px',
                      }}
                    >
                      Demande Envoyée!
                    </h2>
                    <p style={{ fontSize: '15px', color: '#6B7280', marginBottom: '32px' }}>
                      Nous vous contacterons dans les 24 heures pour confirmer votre démonstration.
                    </p>
                    <Link to="/">
                      <button
                        style={{
                          padding: '12px 32px',
                          backgroundColor: 'white',
                          color: '#2D472C',
                          border: '1px solid #2D472C',
                          borderRadius: '4px',
                          fontSize: '15px',
                          fontWeight: '600',
                          cursor: 'pointer',
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.backgroundColor = '#2D472C';
                          e.currentTarget.style.color = 'white';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.backgroundColor = 'white';
                          e.currentTarget.style.color = '#2D472C';
                        }}
                      >
                        Retour à l'accueil
                      </button>
                    </Link>
                  </div>
                )}
              </div>
            </motion.div>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

import { useState } from 'react';
import { motion } from 'motion/react';
import { Navbar } from '../components/Navbar';
import { Footer } from '../components/Footer';
import { CheckCircle, Mail, Phone, MapPin, LayoutDashboard, GraduationCap, Users, BarChart2 } from 'lucide-react';
import { Link } from 'react-router';
import { API_BASE_URL } from '../lib/api';
import { useTranslation } from 'react-i18next';

export default function BookDemo() {
  const { t } = useTranslation();
  const [scrolled, setScrolled] = useState(false);
  const [formSubmitted, setFormSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    schoolName: '',
    email: '',
    phone: '',
    city: '',
    studentCount: '',
    apps: {
      assistant: false,
      teacher: false,
      parent: false,
      manager: false,
    },
    message: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  const handleCheckboxChange = (app: keyof typeof formData.apps) => {
    setFormData({
      ...formData,
      apps: {
        ...formData.apps,
        [app]: !formData.apps[app],
      },
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitError(null);

    // Backend expects Tunisian format: exactly 8 digits (no +216)
    const normalizedPhone = formData.phone.replace(/\s+/g, '').replace(/^\+216/, '');
    if (!/^\d{8}$/.test(normalizedPhone)) {
      setSubmitError(t('bookDemo.form.errors.invalidPhone'));
      return;
    }

    const interestedIn = Object.entries(formData.apps)
      .filter(([, v]) => v)
      .map(([k]) => {
        // Send stable EN identifiers to backend (not translated labels)
        switch (k) {
          case 'assistant':
            return 'Assistant Dashboard';
          case 'teacher':
            return 'Teacher App';
          case 'parent':
            return 'Parent App';
          case 'manager':
            return 'Manager Dashboard';
          default:
            return k;
        }
      });

    const payload = {
      fullName: `${formData.firstName} ${formData.lastName}`.trim(),
      email: formData.email.trim(),
      phone: normalizedPhone,
      schoolName: formData.schoolName.trim(),
      city: formData.city.trim(),
      // This form doesn't collect PRIMARY/SECONDARY/BOTH; default to BOTH.
      schoolType: 'BOTH',
      numberOfStudents: (() => {
        switch (formData.studentCount) {
          case 'less-100':
            return 80;
          case '100-200':
            return 150;
          case '200-400':
            return 300;
          case '400-600':
            return 500;
          case '600+':
            return 650;
          default:
            return 50;
        }
      })(),
      level: null,
      currentSystem: null,
      preferredDate: null,
      preferredTime: null,
      interestedIn,
      message: formData.message ? formData.message : null,
    };

    try {
      setIsSubmitting(true);

      const res = await fetch(`${API_BASE_URL}/api/demo/request`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        const errBody = await res.json().catch(() => null);
        const msg = errBody?.message || errBody?.error || t('bookDemo.form.errors.serverError', { status: res.status });
        throw new Error(msg);
      }

      setFormSubmitted(true);
    } catch (err) {
      setSubmitError(err instanceof Error ? err.message : t('bookDemo.form.errors.submitFailed'));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  return (
    <div style={{ backgroundColor: '#F9F9F7', minHeight: '100vh', fontFamily: 'Inter, sans-serif' }}>
      <Navbar scrolled={scrolled} />

      <div className="relative" style={{ minHeight: '100vh', paddingTop: '80px', paddingBottom: '80px' }}>
        {/* Decorative Circles */}
        <div
          style={{
            position: 'absolute',
            top: '-200px',
            right: '-200px',
            width: '500px',
            height: '500px',
            borderRadius: '50%',
            backgroundColor: '#2D472C',
            opacity: 0.05,
            pointerEvents: 'none',
          }}
        />
        <div
          style={{
            position: 'absolute',
            bottom: '-250px',
            left: '-250px',
            width: '600px',
            height: '600px',
            borderRadius: '50%',
            backgroundColor: '#2D472C',
            opacity: 0.05,
            pointerEvents: 'none',
          }}
        />

        {/* Main Content */}
        <div className="max-w-[1280px] mx-auto px-6 relative z-10">
          <div className="grid lg:grid-cols-2 gap-16 items-center">
            {/* Left Side - Info Panel */}
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            >
              <div
                style={{
                  fontSize: '11px',
                  color: '#C5A059',
                  textTransform: 'uppercase',
                  letterSpacing: '0.1em',
                  fontWeight: '600',
                }}
              >
                {t('bookDemo.hero.badge')}
              </div>
              <h1
                style={{
                  fontFamily: 'Montserrat, sans-serif',
                  fontSize: '44px',
                  fontWeight: '700',
                  color: '#333333',
                  lineHeight: '1.1',
                  marginTop: '16px',
                }}
              >
                {t('bookDemo.hero.title')}
              </h1>
              <p
                style={{
                  fontSize: '16px',
                  color: '#6B7280',
                  lineHeight: '1.7',
                  maxWidth: '420px',
                  marginTop: '20px',
                }}
              >
                {t('bookDemo.hero.subtitle')}
              </p>

              {/* Benefits */}
              <div style={{ marginTop: '40px', display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {(t('bookDemo.hero.benefits', { returnObjects: true }) as string[]).map((benefit, index) => (
                  <div key={index} style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <CheckCircle size={20} style={{ color: '#C5A059', flexShrink: 0 }} />
                    <span style={{ fontSize: '15px', color: '#333333' }}>{benefit}</span>
                  </div>
                ))}
              </div>

              {/* Contact Info */}
              <div style={{ marginTop: '48px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <Mail size={18} style={{ color: '#2D472C', flexShrink: 0 }} />
                  <span style={{ fontSize: '14px', color: '#6B7280' }}>{t('bookDemo.contact.email')}</span>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <Phone size={18} style={{ color: '#2D472C', flexShrink: 0 }} />
                  <span style={{ fontSize: '14px', color: '#6B7280' }}>{t('bookDemo.contact.phone')}</span>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <MapPin size={18} style={{ color: '#2D472C', flexShrink: 0 }} />
                  <span style={{ fontSize: '14px', color: '#6B7280' }}>{t('bookDemo.contact.location')}</span>
                </div>
              </div>
            </motion.div>

            {/* Right Side - Form Card */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            >
              <div
                style={{
                  backgroundColor: 'white',
                  borderRadius: '16px',
                  border: '1px solid #E5E7EB',
                  padding: '40px',
                  boxShadow: '0 8px 32px rgba(0, 0, 0, 0.08)',
                }}
              >
                {!formSubmitted ? (
                  <>
                    <h2
                      style={{
                        fontFamily: 'Montserrat, sans-serif',
                        fontSize: '22px',
                        fontWeight: '600',
                        color: '#333333',
                      }}
                    >
                      {t('bookDemo.form.title')}
                    </h2>

                    <form onSubmit={handleSubmit} style={{ marginTop: '24px' }}>
                      {submitError && (
                        <div
                          style={{
                            marginBottom: '16px',
                            padding: '12px',
                            borderRadius: '8px',
                            backgroundColor: 'rgba(220, 38, 38, 0.06)',
                            border: '1px solid rgba(220, 38, 38, 0.2)',
                            color: '#991B1B',
                            fontSize: '13px',
                            lineHeight: 1.4,
                          }}
                        >
                          {submitError}
                        </div>
                      )}

                      {/* Row 1 - First Name & Last Name */}
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '20px' }}>
                        <div>
                          <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="firstName">
                            {t('bookDemo.form.firstName.label')}
                          </label>
                          <input
                            type="text"
                            id="firstName"
                            name="firstName"
                            required
                            value={formData.firstName}
                            onChange={handleInputChange}
                            placeholder={t('bookDemo.form.firstName.placeholder')}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                        <div>
                          <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="lastName">
                            {t('bookDemo.form.lastName.label')}
                          </label>
                          <input
                            type="text"
                            id="lastName"
                            name="lastName"
                            required
                            value={formData.lastName}
                            onChange={handleInputChange}
                            placeholder={t('bookDemo.form.lastName.placeholder')}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                      </div>

                      {/* Row 2 - School Name */}
                      <div style={{ marginBottom: '20px' }}>
                        <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="schoolName">
                          {t('bookDemo.form.schoolName.label')}
                        </label>
                        <input
                          type="text"
                          id="schoolName"
                          name="schoolName"
                          required
                          value={formData.schoolName}
                          onChange={handleInputChange}
                          placeholder={t('bookDemo.form.schoolName.placeholder')}
                          style={{
                            width: '100%',
                            height: '40px',
                            border: '1px solid #E5E7EB',
                            borderRadius: '4px',
                            padding: '0 12px',
                            fontSize: '14px',
                            color: '#333333',
                            fontFamily: 'Inter, sans-serif',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        />
                      </div>

                      {/* Row 3 - Email & Phone */}
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '20px' }}>
                        <div>
                          <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="email">
                            {t('bookDemo.form.email.label')}
                          </label>
                          <input
                            type="email"
                            id="email"
                            name="email"
                            required
                            value={formData.email}
                            onChange={handleInputChange}
                            placeholder={t('bookDemo.form.email.placeholder')}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                        <div>
                          <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="phone">
                            {t('bookDemo.form.phone.label')}
                          </label>
                          <input
                            type="tel"
                            id="phone"
                            name="phone"
                            required
                            value={formData.phone}
                            onChange={handleInputChange}
                            placeholder={t('bookDemo.form.phone.placeholder')}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                      </div>

                      {/* Row 4 - City & Student Count */}
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '20px' }}>
                        <div>
                          <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="city">
                            {t('bookDemo.form.city.label')}
                          </label>
                          <input
                            type="text"
                            id="city"
                            name="city"
                            required
                            value={formData.city}
                            onChange={handleInputChange}
                            placeholder={t('bookDemo.form.city.placeholder')}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                        <div>
                          <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="studentCount">
                            {t('bookDemo.form.studentCount.label')}
                          </label>
                          <select
                            id="studentCount"
                            name="studentCount"
                            required
                            value={formData.studentCount}
                            onChange={handleInputChange}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                              backgroundColor: 'white',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          >
                            <option value="">{t('bookDemo.form.studentCount.options.placeholder')}</option>
                            <option value="less-100">{t('bookDemo.form.studentCount.options.less100')}</option>
                            <option value="100-200">{t('bookDemo.form.studentCount.options.between100and200')}</option>
                            <option value="200-400">{t('bookDemo.form.studentCount.options.between200and400')}</option>
                            <option value="400-600">{t('bookDemo.form.studentCount.options.between400and600')}</option>
                            <option value="600+">{t('bookDemo.form.studentCount.options.more600')}</option>
                          </select>
                        </div>
                      </div>

                      {/* Row 5 - Applications Checkboxes */}
                      <div style={{ marginBottom: '20px' }}>
                        <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '12px' }}>
                          {t('bookDemo.form.apps.label')}
                        </label>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                          <div
                            onClick={() => handleCheckboxChange('assistant')}
                            style={{
                              border: formData.apps.assistant ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.assistant ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <LayoutDashboard size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>{t('bookDemo.form.apps.options.assistant')}</span>
                            {formData.apps.assistant && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('teacher')}
                            style={{
                              border: formData.apps.teacher ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.teacher ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <GraduationCap size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>{t('bookDemo.form.apps.options.teacher')}</span>
                            {formData.apps.teacher && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('parent')}
                            style={{
                              border: formData.apps.parent ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.parent ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <Users size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>{t('bookDemo.form.apps.options.parent')}</span>
                            {formData.apps.parent && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>

                          <div
                            onClick={() => handleCheckboxChange('manager')}
                            style={{
                              border: formData.apps.manager ? '1px solid #2D472C' : '1px solid #E5E7EB',
                              backgroundColor: formData.apps.manager ? 'rgba(45, 71, 44, 0.05)' : 'white',
                              borderRadius: '8px',
                              padding: '12px',
                              display: 'flex',
                              alignItems: 'center',
                              gap: '10px',
                              cursor: 'pointer',
                              transition: 'all 0.2s ease-out',
                            }}
                          >
                            <BarChart2 size={18} style={{ color: '#2D472C' }} />
                            <span style={{ fontSize: '13px', color: '#333333', flex: 1 }}>{t('bookDemo.form.apps.options.manager')}</span>
                            {formData.apps.manager && <CheckCircle size={16} style={{ color: '#2D472C' }} />}
                          </div>
                        </div>
                      </div>

                      {/* Row 6 - Message */}
                      <div style={{ marginBottom: '24px' }}>
                        <label style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }} htmlFor="message">
                          {t('bookDemo.form.message.label')}
                        </label>
                        <textarea
                          id="message"
                          name="message"
                          value={formData.message}
                          onChange={handleInputChange}
                          placeholder={t('bookDemo.form.message.placeholder')}
                          rows={4}
                          style={{
                            width: '100%',
                            border: '1px solid #E5E7EB',
                            borderRadius: '4px',
                            padding: '12px',
                            fontSize: '14px',
                            color: '#333333',
                            fontFamily: 'Inter, sans-serif',
                            resize: 'vertical',
                            minHeight: '100px',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        />
                      </div>

                      {/* Submit Button */}
                      <button
                        type="submit"
                        disabled={isSubmitting}
                        style={{
                          width: '100%',
                          height: '48px',
                          backgroundColor: '#2D472C',
                          color: 'white',
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '15px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          border: 'none',
                          cursor: isSubmitting ? 'not-allowed' : 'pointer',
                          opacity: isSubmitting ? 0.75 : 1,
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '0.9';
                        }}
                        onMouseLeave={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '1';
                        }}
                      >
                        {isSubmitting ? t('bookDemo.form.submit.submitting') : t('bookDemo.form.submit.label')}
                      </button>

                      {/* Note */}
                      <div style={{ fontSize: '12px', color: '#9CA3AF', textAlign: 'center', marginTop: '12px' }}>
                        {t('bookDemo.form.trustLine')}
                      </div>
                    </form>
                  </>
                ) : (
                  /* Success State */
                  <div style={{ textAlign: 'center', padding: '40px 0' }}>
                    <CheckCircle size={64} style={{ color: '#C5A059', margin: '0 auto 24px' }} />
                    <h2
                      style={{
                        fontFamily: 'Montserrat, sans-serif',
                        fontSize: '24px',
                        fontWeight: '700',
                        color: '#333333',
                        marginBottom: '12px',
                      }}
                    >
                      {t('bookDemo.success.title')}
                    </h2>
                    <p style={{ fontSize: '15px', color: '#6B7280', marginBottom: '32px' }}>{t('bookDemo.success.subtitle')}</p>
                    <Link to="/">
                      <button
                        style={{
                          padding: '12px 32px',
                          backgroundColor: 'white',
                          color: '#2D472C',
                          border: '1px solid #2D472C',
                          borderRadius: '4px',
                          fontSize: '15px',
                          fontWeight: '600',
                          cursor: 'pointer',
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.backgroundColor = '#2D472C';
                          e.currentTarget.style.color = 'white';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.backgroundColor = 'white';
                          e.currentTarget.style.color = '#2D472C';
                        }}
                      >
                        {t('bookDemo.success.backHome')}
                      </button>
                    </Link>
                  </div>
                )}
              </div>
            </motion.div>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

/* Contact page - hero right image styles */

.contact-hero-media {
  width: 100%;
  max-width: 580px;
  height: 420px;
  height: 420px;
  height: 420px;
  height: 420px;
  height: 420px;
  height: 420px;
  height: 420px;
  height: 420px;
  height: 420px;

/* Contact page - hero right image styles */

.contact-hero-media {
  width: 100%;
  max-width: 580px;
  margin-left: auto;
  position: relative;
  overflow: hidden;

  border-radius: 18px;
  border: 1.5px solid rgba(45, 71, 44, 0.38);

  background:
    radial-gradient(120% 120% at 0% 0%, rgba(197, 160, 89, 0.20) 0%, rgba(255, 255, 255, 0) 55%),
    linear-gradient(135deg, rgba(45, 71, 44, 0.12), rgba(197, 160, 89, 0.10));

  box-shadow:
    0 18px 48px rgba(0, 0, 0, 0.10),
    0 0 0 6px rgba(45, 71, 44, 0.08),
    0 24px 70px rgba(45, 71, 44, 0.12);

  transition: transform 220ms ease, box-shadow 220ms ease, border-color 220ms ease;

  /*
    Make the block follow the image proportions.
    Update these numbers if c1.png has a different ratio.
  */
  aspect-ratio: 4 / 3;
  height: auto;

  /* keep it reasonable on very small/large screens */
  min-height: 280px;
  max-height: 520px;
}

/* Fallback for browsers without aspect-ratio support */
@supports not (aspect-ratio: 1 / 1) {
  .contact-hero-media {
    height: 420px;
  }
}

.contact-hero-media:hover {
  transform: translateY(-3px);
  border-color: rgba(45, 71, 44, 0.55);
  box-shadow:
    0 22px 60px rgba(0, 0, 0, 0.12),
    0 0 0 7px rgba(45, 71, 44, 0.10),
    0 30px 90px rgba(45, 71, 44, 0.16);
}

.contact-hero-media__img {
  position: absolute;
  inset: 0;
  z-index: 1;

  /* Preserve the full image (no cropping / no distortion) */
  width: 100%;
  height: 100%;
  object-fit: contain;
  object-position: center;

  /* remove padding so the full image is visible */
  padding: 0;

  /* nicer rendering */
  transform: translateZ(0);
  image-rendering: auto;
  filter: saturate(1.05) contrast(1.03);

  /* If you prefer a full-frame look (with crop), switch to cover */
  /* object-fit: cover; */
}

.contact-hero-media__overlay {
  position: absolute;
  inset: 0;
  z-index: 2;
  pointer-events: none;

  border-radius: 18px;

  /* Slightly softer overlay to keep the image readable */
  background: linear-gradient(
    180deg,
    rgba(45, 71, 44, 0.18) 0%,
    rgba(45, 71, 44, 0.08) 55%,
    rgba(0, 0, 0, 0.16) 100%
  );
}

.contact-hero-media__badges {
  position: absolute;
  left: 18px;
  right: 18px;
  bottom: 18px;
  z-index: 3;

  display: flex;
  flex-direction: column;
  gap: 10px;
}

.contact-hero-media__badgePrimary {
  display: inline-flex;
  align-items: center;
  width: fit-content;

  padding: 10px 14px;
  border-radius: 999px;

  color: #fff;
  font-family: Montserrat, sans-serif;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.2px;

  background: linear-gradient(135deg, rgba(45, 71, 44, 0.92), rgba(45, 71, 44, 0.62));
  border: 1px solid rgba(255, 255, 255, 0.18);
  box-shadow: 0 10px 22px rgba(0, 0, 0, 0.18);
}

.contact-hero-media__badgeSecondary {
  display: inline-flex;
  align-items: center;
  width: fit-content;

  padding: 8px 12px;
  border-radius: 999px;

  color: #fff;
  font-family: Inter, sans-serif;
  font-size: 14px;
  font-weight: 500;

  background-color: rgba(0, 0, 0, 0.35);
  border: 1px solid rgba(255, 255, 255, 0.14);
  -webkit-backdrop-filter: blur(6px);
  backdrop-filter: blur(6px);
}

/* Small screens: give a bit more height */
@media (max-width: 640px) {
  .contact-hero-media {
    max-width: 100%;
    min-height: 240px;
  }
}

import { useState } from 'react';
import { motion } from 'motion/react';
import { Navbar } from '../components/Navbar';
import { Footer } from '../components/Footer';
import { Calendar, MessageSquare, Headphones, MapPin, Mail, Phone, Clock, CheckCircle, ChevronDown, ChevronUp, Linkedin, Facebook, Instagram } from 'lucide-react';
import { Link } from 'react-router';
import { apiPost } from '../lib/api';
import c1Image from '../../assets/contact.png';
import './Contact.css';
import { useTranslation } from 'react-i18next';

export default function Contact() {
  const { t } = useTranslation();
  const [scrolled, setScrolled] = useState(false);
  const [formSubmitted, setFormSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    subject: '',
    message: '',
  });
  const [activeAccordion, setActiveAccordion] = useState<number | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitError(null);
    setIsSubmitting(true);

    try {
      const payload = {
        name: `${formData.firstName} ${formData.lastName}`.trim(),
        email: formData.email,
        phone: formData.phone,
        subject: formData.subject,
        message: formData.message,
      };

      await apiPost('/api/contact/submit', payload);

      setFormSubmitted(true);
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        subject: '',
        message: '',
      });
    } catch (err: any) {
      setSubmitError(err?.message ?? "Erreur lors de l'envoi du message.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const toggleAccordion = (index: number) => {
    setActiveAccordion(activeAccordion === index ? null : index);
  };

  const scrollToContactForm = () => {
    const el = document.getElementById('contact-form');
    el?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const faqs = [
    {
      question: t('contact.page.faq.items.0.q'),
      answer: t('contact.page.faq.items.0.a'),
    },
    {
      question: t('contact.page.faq.items.1.q'),
      answer: t('contact.page.faq.items.1.a'),
    },
    {
      question: t('contact.page.faq.items.2.q'),
      answer: t('contact.page.faq.items.2.a'),
    },
    {
      question: t('contact.page.faq.items.3.q'),
      answer: t('contact.page.faq.items.3.a'),
    },
  ];

  return (
    <div style={{ backgroundColor: '#F9F9F7', minHeight: '100vh', fontFamily: 'Inter, sans-serif' }}>
      <Navbar scrolled={scrolled} />

      {/* Section 1 - Hero */}
      <section style={{ backgroundColor: 'white', paddingTop: '100px', paddingBottom: '100px', position: 'relative', overflow: 'hidden' }}>
        {/* Decorative Circle - Top Left */}
        <div
          style={{
            position: 'absolute',
            top: '-285px',
            left: '-285px',
            width: '380px',
            height: '380px',
            borderRadius: '50%',
            backgroundColor: 'rgba(45, 71, 44, 0.06)',
            pointerEvents: 'none',
          }}
        />

        {/* Decorative Circle - Bottom Right */}
        <div
          style={{
            position: 'absolute',
            bottom: '-240px',
            right: '-240px',
            width: '320px',
            height: '320px',
            borderRadius: '50%',
            backgroundColor: 'rgba(45, 71, 44, 0.06)',
            pointerEvents: 'none',
          }}
        />

        <div className="max-w-[1280px] mx-auto px-6 relative z-10">
          <div className="grid lg:grid-cols-[45%_55%] gap-16 items-center">
            {/* Left side - Text */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            >
              <h1
                style={{
                  fontFamily: 'Montserrat, sans-serif',
                  fontSize: '44px',
                  fontWeight: '700',
                  color: '#333333',
                  lineHeight: '1.1',
                  maxWidth: '440px',
                  marginBottom: '20px',
                }}
              >
                {t('contact.page.heroTitle')}
              </h1>
              <p
                style={{
                  fontSize: '15px',
                  color: '#6B7280',
                  lineHeight: '1.7',
                  maxWidth: '420px',
                }}
              >
                {t('contact.page.heroSubtitle')}
              </p>
            </motion.div>

            {/* Right side - Image */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, ease: 'easeOut', delay: 0.2 }}
              className="contact-hero-media"
            >
              <img src={c1Image} alt={t('contact.hero.imageAlt')} className="contact-hero-media__img" />
              <div className="contact-hero-media__overlay" />
              <div className="contact-hero-media__badges">
                <span className="contact-hero-media__badgePrimary">{t('contact.hero.badgePrimary')}</span>
                <span className="contact-hero-media__badgeSecondary">{t('contact.hero.badgeSecondary')}</span>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Section 2 - 3 Contact Cards */}
      <section style={{ backgroundColor: 'white', paddingTop: '60px', paddingBottom: '60px' }}>
        <div className="max-w-[1280px] mx-auto px-6">
          <div className="grid md:grid-cols-3 gap-6 items-stretch">
            {/* Card 1 - Book a demo */}
            <motion.div
