              <p style={{ fontSize: '14px', color: '#6B7280', lineHeight: '1.6', marginBottom: '20px' }}>
                {t('contact.page.cards.sales.description')}
              </p>

              <div style={{ marginTop: 'auto' }}>
                <button
                  type="button"
                  className="transition-all duration-200"
                  style={{
                    width: '100%',
                    height: '40px',
                    backgroundColor: 'white',
                    color: '#2D472C',
                    borderRadius: '4px',
                    border: '1px solid #2D472C',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'pointer',
                  }}
                  onClick={scrollToContactForm}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#2D472C';
                    e.currentTarget.style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'white';
                    e.currentTarget.style.color = '#2D472C';
                  }}
                >
                  {t('contact.page.cards.sales.button')}
                </button>

                {/* keep same bottom spacing across cards */}
                <div style={{ height: '28px' }} aria-hidden="true" />
              </div>
            </motion.div>

            {/* Card 3 - Support */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.4, ease: 'easeOut', delay: 0.2 }}
              className="transition-all duration-200"
              style={{
                backgroundColor: 'white',
                border: '1px solid #E5E7EB',
                borderRadius: '16px',
                padding: '32px',
                textAlign: 'center',

                display: 'flex',
                flexDirection: 'column',
                height: '100%',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.borderColor = '#2D472C')}
              onMouseLeave={(e) => (e.currentTarget.style.borderColor = '#E5E7EB')}
            >
              <Headphones size={36} style={{ color: '#C5A059', margin: '0 auto 16px' }} />
              <h3
                style={{
                  fontFamily: 'Montserrat, sans-serif',
                  fontSize: '18px',
                  fontWeight: '600',
                  color: '#333333',
                  marginBottom: '12px',
                }}
              >
                {t('contact.page.cards.support.title')}
              </h3>
              <p style={{ fontSize: '14px', color: '#6B7280', lineHeight: '1.6', marginBottom: '20px' }}>
                {t('contact.page.cards.support.description')}
              </p>

              <div style={{ marginTop: 'auto' }}>
                <button
                  type="button"
                  disabled
                  aria-disabled="true"
                  className="transition-all duration-200"
                  style={{
                    width: '100%',
                    height: '40px',
                    backgroundColor: '#F3F4F6',
                    color: '#9CA3AF',
                    borderRadius: '4px',
                    border: '1px solid #E5E7EB',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: 'not-allowed',
                  }}
                >
                  {t('contact.page.cards.support.button')}
                </button>
                <div
                  style={{
                    marginTop: '10px',
                    height: '18px',
                    fontSize: '13px',
                    color: '#2D472C',
                    fontWeight: 600,
                  }}
                >
                  N'est pas disponible pour le moment
                </div>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Section 3 - Contact Form + Info */}
      <section style={{ backgroundColor: '#F9F9F7', paddingTop: '80px', paddingBottom: '80px' }}>
        <div className="max-w-[1280px] mx-auto px-6">
          <div className="grid lg:grid-cols-[55%_45%] gap-12">
            {/* Left - Contact Form */}
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            >
              <div
                id="contact-form"
                style={{
                  backgroundColor: 'white',
                  borderRadius: '16px',
                  border: '1px solid #E5E7EB',
                  padding: '40px',
                }}
              >
                {!formSubmitted ? (
                  <>
                    <h2
                      style={{
                        fontFamily: 'Montserrat, sans-serif',
                        fontSize: '22px',
                        fontWeight: '600',
                        color: '#333333',
                        marginBottom: '24px',
                      }}
                    >
                      {t('contact.page.form.title')}
                    </h2>

                    <form onSubmit={handleSubmit}>
                      {/* Row 1 - First Name & Last Name */}
