                          fontWeight: '600',
                          borderRadius: '4px',
                          border: 'none',
                          cursor: isSubmitting ? 'not-allowed' : 'pointer',
                          transition: 'all 0.2s ease-out',
                          opacity: isSubmitting ? 0.85 : 1,
                        }}
                        onMouseEnter={(e) => {
