                            fontFamily: 'Inter, sans-serif',
                            resize: 'vertical',
                            minHeight: '120px',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        />
                      </div>

                      {/* Submit Button */}
                      {submitError && (
                        <div
                          role="alert"
                          style={{
                            marginBottom: '12px',
                            padding: '10px 12px',
                            borderRadius: '6px',
                            border: '1px solid rgba(239, 68, 68, 0.35)',
                            backgroundColor: 'rgba(239, 68, 68, 0.08)',
                            color: '#991B1B',
                            fontSize: '13px',
                          }}
                        >
                          {submitError}
                        </div>
                      )}

                      <button
                        type="submit"
                        disabled={isSubmitting}
                        style={{
                          width: '100%',
                          height: '48px',
                          backgroundColor: '#2D472C',
                          color: 'white',
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '15px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          border: 'none',
                          cursor: isSubmitting ? 'not-allowed' : 'pointer',
                          transition: 'all 0.2s ease-out',
                          opacity: isSubmitting ? 0.85 : 1,
                        }}
                        onMouseEnter={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '0.9';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.opacity = isSubmitting ? '0.85' : '1';
                        }}
                      >
                        {isSubmitting ? t('contact.page.form.submitting') : t('contact.page.form.submit')}
                      </button>
