                          fontFamily: 'Inter, sans-serif',
                          fontSize: '14px',
                          fontWeight: '600',
                          color: '#333333',
                          marginBottom: '4px',
                        }}
                      >
                        {t('contact.page.info.phoneLabel')}
                      </div>
                      <div style={{ fontSize: '14px', color: '#6B7280' }}>+216 XX XXX XXX</div>
