                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                    textDecoration: 'none',
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLAnchorElement).style.backgroundColor = '#2D472C';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLAnchorElement).style.backgroundColor = 'white';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = '#2D472C';
                  }}
                >
                  <Facebook size={18} style={{ color: '#2D472C', transition: 'color 0.2s ease-out' }} />
                </a>

                {/* Instagram */}
                <a
                  href="https://www.instagram.com/omnilinks.tn/?hl=fr"
                  target="_blank"
                  rel="noreferrer"
                  aria-label="Instagram"
                  className="transition-all duration-200"
                  style={{
                    width: '40px',
                    height: '40px',
                    border: '1px solid #2D472C',
                    borderRadius: '8px',
                    backgroundColor: 'white',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                    textDecoration: 'none',
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLAnchorElement).style.backgroundColor = '#2D472C';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLAnchorElement).style.backgroundColor = 'white';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = '#2D472C';
                  }}
                >
                  <Instagram size={18} style={{ color: '#2D472C', transition: 'color 0.2s ease-out' }} />
                </a>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Section 5 - FAQ Strip */}
      <section style={{ backgroundColor: '#F9F9F7', paddingTop: '60px', paddingBottom: '60px' }}>
        <div className="max-w-[1280px] mx-auto px-6">
          <h2
            style={{
              fontFamily: 'Montserrat, sans-serif',
              fontSize: '32px',
              fontWeight: '700',
              color: '#333333',
              textAlign: 'center',
              marginBottom: '40px',
            }}
          >
            {t('contact.page.faq.title')}
          </h2>

          <div style={{ maxWidth: '800px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {faqs.map((faq, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 10 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.4, ease: 'easeOut', delay: index * 0.1 }}
                style={{
                  backgroundColor: 'white',
                  border: '1px solid #E5E7EB',
                  borderRadius: '8px',
                  padding: '20px',
                }}
              >
                <div
                  onClick={() => toggleAccordion(index)}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    cursor: 'pointer',
                  }}
                >
                  <div
                    style={{
                      fontFamily: 'Inter, sans-serif',
                      fontSize: '15px',
                      fontWeight: '600',
                      color: activeAccordion === index ? '#2D472C' : '#333333',
                      transition: 'color 0.2s ease-out',
                    }}
                  >
                    {faq.question}
                  </div>
                  {activeAccordion === index ? (
                    <ChevronUp size={20} style={{ color: '#2D472C', flexShrink: 0 }} />
                  ) : (
                    <ChevronDown size={20} style={{ color: '#6B7280', flexShrink: 0 }} />
                  )}
                </div>
                {activeAccordion === index && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    transition={{ duration: 0.3, ease: 'easeOut' }}
                    style={{
                      overflow: 'hidden',
                      paddingTop: '12px',
                      fontSize: '14px',
                      color: '#6B7280',
                      lineHeight: '1.6',
                    }}
                  >
                    {faq.answer}
                  </motion.div>
                )}
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
}

