                    <div
                      style={{
                        display: 'inline-block',
                        padding: '4px 8px',
                        backgroundColor: '#F9F9F7',
                        borderRadius: '4px',
                        fontSize: '11px',
                        fontWeight: '600',
                        color: '#333333'
                      }}
                    >
                      {screen}
                    </div>
                    {/* Content - Charts */}
                    <div style={{ marginTop: '12px' }}>
                      {index === 0 ? (
                        // Chart bars for Statistics
                        <div style={{ display: 'flex', alignItems: 'flex-end', gap: '4px', height: '80px' }}>
                          {[50, 70, 40, 90, 60].map((height, i) => (
                            <div
                              key={i}
                              style={{
                                flex: 1,
                                height: `${height}%`,
                                backgroundColor: '#C5A059',
                                borderRadius: '2px'
                              }}
                            ></div>
                          ))}
                        </div>
                      ) : (
                        // Regular rows for Finance/Reports
                        [1, 2, 3].map((i) => (
                          <div
                            key={i}
                            style={{
                              height: '30px',
                              backgroundColor: '#E5E7EB',
                              borderRadius: '4px',
                              marginBottom: '8px'
                            }}
                          ></div>
                        ))
                      )}
                    </div>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Section 4 - CTA Banner */}
      <section className="py-24 px-6" style={{ backgroundColor: '#2D472C' }}>
        <div className="max-w-[1280px] mx-auto text-center">
          <h2
            style={{ 
              fontFamily: 'Montserrat, sans-serif', 
              fontSize: '36px', 
              fontWeight: '700', 
              color: 'white',
              marginBottom: '16px'
            }}
          >
            {t('managerDashboard.cta.title')}
          </h2>
          <p style={{ fontSize: '16px', color: 'rgba(255, 255, 255, 0.8)', marginBottom: '32px' }}>
            {t('managerDashboard.cta.subtitle')}
          </p>
          <Link to="/book-demo">
            <button
              className="transition-all duration-200 hover:opacity-90"
              style={{
                backgroundColor: '#C5A059',
                color: '#2D472C',
                borderRadius: '4px',
                padding: '0 32px',
                height: '48px',
                fontSize: '15px',
                fontWeight: '600'
              }}
            >
              {t('managerDashboard.cta.button')}
            </button>
          </Link>
        </div>
      </section>

      <Footer />
    </div>
  );
}

